package main
import ("context";"encoding/json";"net/http";"time";"github.com/go-chi/chi/v5";"github.com/jackc/pgx/v5/pgxpool")
func main(){db,_:=pgxpool.New(context.Background(),"postgres://postgres:postgres@postgres:5432/hypercompute?sslmode=disable");r:=chi.NewRouter();r.Get("/health",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("ok"))});r.Get("/metrics",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("scheduler_up 1"))});r.Post("/nodes/register",func(w http.ResponseWriter,r *http.Request){var b map[string]any;json.NewDecoder(r.Body).Decode(&b);_,_=db.Exec(r.Context(),"insert into nodes(node_id,owner_user_id,base_url,pool,reputation_score,health_score,gpu_usage,active_requests,last_heartbeat_at,status,created_at) values($1,$2,$3,'community',100,100,0,0,now(),'online',now()) on conflict(node_id) do update set base_url=excluded.base_url",b["node_id"],int(b["owner_user_id"].(float64)),b["base_url"]);json.NewEncoder(w).Encode(map[string]any{"ok":true})});r.Post("/nodes/heartbeat",func(w http.ResponseWriter,r *http.Request){var b map[string]any;json.NewDecoder(r.Body).Decode(&b);_,_=db.Exec(r.Context(),"update nodes set last_heartbeat_at=now(),status='online' where node_id=$1",b["node_id"]);json.NewEncoder(w).Encode(map[string]any{"ok":true})});r.Post("/schedule",func(w http.ResponseWriter,r *http.Request){var b map[string]any;json.NewDecoder(r.Body).Decode(&b);var id,url string;_ = db.QueryRow(r.Context(),"select node_id,base_url from nodes where owner_user_id<>$1 and status='online' and now()-last_heartbeat_at < interval '30 second' order by reputation_score desc, health_score desc,gpu_usage asc,active_requests asc limit 1",int(b["user_id"].(float64))).Scan(&id,&url);json.NewEncoder(w).Encode(map[string]any{"node_id":id,"base_url":url,"ts":time.Now()})});http.ListenAndServe(":8081",r)}
